    "target_name": "MDM2",
    "target_overview": (
        "MDM2 (UniProt Q00987) is a human E3 ubiquitin-protein ligase and key negative regulator of p53. "
        "It is a major oncology target because it suppresses p53-mediated tumor suppression. "
        "The best-characterized binderable site is the N-terminal p53-binding domain, which contains a hydrophobic cleft "
        "used by p53, p53-mimetic peptides, and Nutlin-class inhibitors."
    ),
    "sabdab_hits": [
        {
            "source": "SAbDab",
            "status": "not directly queried in this environment",
            "summary": (
                "Known structural binder literature exists for MDM2, especially to the N-terminal p53-binding pocket. "
                "No specific SAbDab entry IDs were retrieved here."
            ),
        }
    ],
    "iedb_hits": [
        {
            "source": "IEDB",
            "status": "not directly queried in this environment",
            "summary": (
                "MDM2 has reported immune epitopes in cancer/immunology contexts. "
                "Likely most relevant are epitopes in the exposed N-terminal domain rather than the disordered acidic region."
            ),
        }
    ],
    "web_findings": [
        "MDM2 is frequently discussed as a therapeutic target in cancer due to p53 pathway suppression.",
        "Most structural and ligand-binding studies focus on the N-terminal hydrophobic cleft.",
        "Peptide and small-molecule antagonists often compete directly with p53 binding.",
        "MDM2/MDMX (MDM4) homology suggests potential cross-reactivity concerns for binders.",
    ],
    "design_constraints": [
        "Prioritize the N-terminal p53-binding domain for binder characterization.",
        "Expect competition with endogenous p53 for any binder targeting the primary pocket.",
        "Consider selectivity against MDM4/MDMX because of homologous N-terminal p53-binding domains.",
        "Long acidic/disordered regions are less attractive as primary epitopes.",
        "RING-domain binding may affect function but is less established than N-terminal targeting.",
    ],
    "notable_epitopes": [
        {
            "region": "N-terminal p53-binding groove",
