            "importance": "Primary hotspot for known ligands, peptides, and small molecules.",
        },
        {
            "region": "Hydrophobic cleft within N-terminus",
            "approx_residues": "1-120",
            "importance": "Key contact surface for p53-mimetic binders.",
        },
    ],
}

print(json.dumps(research_summary, indent=2, default=str))

